import (
	"html/template"
	"net/http"
)

// HandleProductSearch handles the product search request and renders the result safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template.
	// We use the html/template package to ensure the 'keyword' is automatically escaped,
	// preventing Cross-Site Scripting (XSS) attacks.
	const tpl = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("searchResult").Parse(tpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template, passing the keyword as the data to be rendered.
	// If the keyword contains characters like <script>, they will be escaped to &lt;script&gt;
	if err := t.Execute(w, keyword); err != nil {
		// If writing the response fails, we can't really write an http.Error 
		// because the header has likely already been sent (status 200).
		// In a production environment, you would log this error.
		return
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

