package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It extracts the 'keyword' query parameter, logs the search for analytics,
// and renders an HTML page displaying the search term safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the URL query parameters.
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event.
	// In a production environment, this might send data to a data warehouse or metrics system.
	// Here, we use the standard logger to record the event.
	log.Printf("[Analytics] Search Event - Keyword: %q, IP: %s, Time: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Define the HTML template.
	// We use html/template to ensure the keyword is automatically escaped,
	// preventing Cross-Site Scripting (XSS) attacks.
	const htmlTpl = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the page title area -->
    <h2>Search Results: {{.}}</h2>

    <hr>
    <p><em>Analytics logged for this query.</em></p>
</body>
</html>`

	// 4. Parse the template.
	t, err := template.New("searchResult").Parse(htmlTpl)
	if err != nil {
		log.Printf("Template parsing error: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// 5. Set the Content-Type header.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 6. Execute the template with the keyword as data.
	if err := t.Execute(w, keyword); err != nil {
		log.Printf("Template execution error: %v", err)
		// Note: We cannot send http.Error here if the header has already been written.
	}
}

func main() {
	// Register the handler.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server.
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=laptop", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

