package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the search request, logs analytics, and renders the result page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Parse the query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// We log the search event. In a production system, this might push to a queue (Kafka) or DB.
	// Using standard log package to simulate analytics tracking.
	log.Printf("[Analytics] Timestamp=%s | IP=%s | Action=Search | Keyword=%s",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		keyword,
	)

	// 3. XSS Prevention
	// Since we are reflecting user input back into the HTML, we MUST escape it
	// to prevent Cross-Site Scripting (XSS) attacks.
	safeKeyword := html.EscapeString(keyword)

	// 4. Set Content-Type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Render HTML
	// We use Fprintf to write the response.
	// The requirement is to display: <h2>Search Results: [keyword]</h2>
	htmlResponse := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Page</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Analytics tracked for this search.</p>
</body>
</html>`, safeKeyword)

	fmt.Fprint(w, htmlResponse)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server is running. Try: http://localhost%s/search?keyword=Laptop\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

