package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It extracts the keyword, logs an analytics event, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests for search
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support:
	// In a real production environment, this would likely send data to a message queue
	// or an external analytics service (e.g., Google Analytics, Mixpanel, internal DB).
	// Here we simulate the analytics recording.
	go func(k string, userAgent string) {
		// Log the search event asynchronously to avoid blocking the response
		log.Printf("[Analytics] Event: Search | Keyword: %q | Time: %s | UA: %s",
			k, time.Now().Format(time.RFC3339), userAgent)
	}(keyword, r.UserAgent())

	// Security: Prevent Cross-Site Scripting (XSS).
	// Since we are reflecting user input directly into the HTML,
	// we MUST escape special characters (e.g., <, >, &, ", ').
	safeKeyword := html.EscapeString(keyword)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	// Render the HTML response
	// Using fmt.Fprintf to write the formatted string to the ResponseWriter.
	htmlContent := `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <header>
        <h1>My E-Commerce Site</h1>
    </header>
    <main>
        <!-- Requirement: Display the user's search keyword in the page title area -->
        <h2>Search Results: %s</h2>

        <p>Showing results for your search...</p>
        <!-- Product list logic would be implemented here -->
    </main>
</body>
</html>`

	fmt.Fprintf(w, htmlContent, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=golang", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

