	"time"
)

// SearchPageData holds the data to be rendered in the HTML template.
type SearchPageData struct {
	Keyword string
}

// HandleProductSearch handles the product search request.
// It logs the search event for analytics and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// Since we are restricted to the standard library, we implement analytics
	// by logging structured data to stdout. In a production environment,
	// this would likely be sent to a data warehouse or analytics service.
	log.Printf(
		"[ANALYTICS] Event: Search | Keyword: %q | IP: %s | User-Agent: %s | Time: %s",
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
		time.Now().Format(time.RFC3339),
	)

	// 3. Define the HTML Template
	// We use html/template to ensure context-aware escaping of the keyword.
	// This prevents XSS attacks if the user inputs malicious scripts.
	const htmlTpl = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <style>
        body { font-family: sans-serif; padding: 20px; }
        .results-header { margin-bottom: 20px; }
    </style>
</head>
<body>
    <div class="results-header">
        <!-- Requirement: Display the user's search keyword -->
        <h2>Search Results: {{.Keyword}}</h2>
    </div>

    <div class="product-list">
        <!-- Product results would be iterated here -->
        <p><em>(Displaying results for safe rendering verification...)</em></p>
    </div>
</body>
</html>`

	// 4. Parse the template
	tmpl, err := template.New("search_results").Parse(htmlTpl)
	if err != nil {
		log.Printf("Error parsing template: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// 5. Set Response Headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 6. Execute the template
	// If the keyword is empty, it will simply render "Search Results: "
	data := SearchPageData{
		Keyword: keyword,
	}

	if err := tmpl.Execute(w, data); err != nil {
		log.Printf("Error executing template: %v", err)
		// Note: We cannot write http.Error here if the header has already been written
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s", port)
	log.Printf("Try visiting: http://localhost%s/search?keyword=Golang", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

