	t, err := template.New("search_results").Parse(tpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template using the keyword as data.
	// html/template automatically escapes the input (e.g., "<" becomes "&lt;")
