// HandleProductSearch handles the product search request, logs analytics, and renders the response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a production environment, this might send data to a message queue or database.
	// Here we log the search event to stdout with a timestamp.
	log.Printf("[Analytics] Event: Search | Keyword: %q | IP: %s | Time: %s", 
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Prepare the template
	// Parsing the template on every request is inefficient for high load, 
	// but acceptable for this specific function implementation scope.
	tmpl, err := template.New("search").Parse(htmlTemplate)
	if err != nil {
		log.Printf("Template parsing error: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// 4. Set Content-Type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Render the response
	// The template engine automatically escapes the keyword, neutralizing XSS vectors.
	data := PageData{
		Keyword: keyword,
	}

	if err := tmpl.Execute(w, data); err != nil {
		log.Printf("Template execution error: %v", err)
		// If the header was already written, this error might not be visible to the client
		return
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on :8080...")
	log.Println("Try visiting: http://localhost:8080/search?keyword=Golang")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

