package main

import (
	"html/template"
	"net/http"
)

// HandleProductSearch handles the product search request and renders the results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML structure using html/template.
	// We use a template instead of string concatenation to automatically 
	// escape the 'keyword' variable, preventing Reflected XSS attacks.
	const responseTemplate = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("search").Parse(responseTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the keyword as the data.
	// {{.}} in the template will be replaced by the sanitized keyword.
	if err := t.Execute(w, keyword); err != nil {
		// In a production environment, you would log this error.
		http.Error(w, "Error rendering response", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server (listening on port 8080 for demonstration)
	http.ListenAndServe(":8080", nil)
}

