type SearchAnalyticsEvent struct {
	Type      string    `json:"type"`
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
	RemoteAddr string   `json:"remote_addr"`
}

// HandleProductSearch handles the product search request, logs analytics,
// and renders the HTML response safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from the query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// Log the search event as JSON to stdout (standard practice for log aggregators)
	event := SearchAnalyticsEvent{
		Type:       "search_query",
		Keyword:    keyword,
		Timestamp:  time.Now(),
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
	}

	// We ignore the error here as analytics logging failure shouldn't break the user request,
	// but in a production system, you might want to handle this differently.
	_ = json.NewEncoder(os.Stdout).Encode(event)

	// 3. Render the HTML response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// We use html/template to ensure the keyword is automatically escaped.
	// This prevents Cross-Site Scripting (XSS) attacks if the keyword contains malicious scripts.
	const tpl = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- The keyword is rendered here. html/template handles escaping automatically. -->
    <h2>Search Results: {{.}}</h2>
</body>
</html>`

	t, err := template.New("search_results").Parse(tpl)
	if err != nil {
		// If the template fails to parse (server-side error), return 500
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	// Execute the template with the keyword data
	if err := t.Execute(w, keyword); err != nil {
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=example", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

