package main

import (
	"html/template"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log the search keyword
	log.Printf("Search event: keyword='%s'", keyword)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Use html/template to prevent Cross-Site Scripting (XSS).
	// Direct string concatenation with user input is a security vulnerability.
	const htmlTemplate = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("search_results").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	// Execute the template, passing the keyword as data.
	// The template engine automatically escapes special characters in the keyword.
	if err := t.Execute(w, keyword); err != nil {
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server started on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

