package main

import (
	"html/template"
	"net/http"
)

// HandleProductSearch handles the product search request and renders the result safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML content using the html/template package.
	// This is the secure way to handle user input in HTML.
	// The {{.}} placeholder will automatically escape the input (e.g., converting < to &lt;),
	// preventing Cross-Site Scripting (XSS) attacks.
	const tpl = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("search_results").Parse(tpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the user-provided keyword
	if err := t.Execute(w, keyword); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

