func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a real-world scenario, this would likely send data to an analytics service (e.g., Kafka, DB).
	// Here, we log the search event to stdout to satisfy the requirement using only stdlib.
	log.Printf("[Analytics] Time: %s | IP: %s | User-Agent: %s | Search Keyword: %q",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
		keyword,
	)

	// 3. Prepare the HTML response
	// We use html/template to ensure the keyword is properly escaped.
	// This prevents Cross-Site Scripting (XSS) attacks if the keyword contains malicious scripts.
	const htmlTemplate = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- The keyword is injected here. The template engine handles HTML escaping automatically. -->
    <h2>Search Results: {{.}}</h2>
</body>
</html>`

	t, err := template.New("search_page").Parse(htmlTemplate)
	if err != nil {
		// In case of a template parsing error (unlikely with a const string), return 500
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	// 4. Set Content-Type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Render the template
	err = t.Execute(w, keyword)
	if err != nil {
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	addr := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=golang", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatal(err)
	}
}

