package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests.
// It retrieves the keyword, logs an analytics event, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Retrieve the 'keyword' from the URL query parameters.
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support.
	// We log the search action. In a real-world scenario, this might send an event
	// to a message queue (e.g., Kafka) or an analytics database.
	log.Printf("[Analytics] Time: %s | IP: %s | Search: %s",
		time.Now().Format(time.RFC3339), r.RemoteAddr, keyword)

	// 3. Set the Content-Type header to HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Security: Prevent Cross-Site Scripting (XSS).
	// Since we are reflecting user input (the keyword) back into the HTML,
	// we MUST escape special characters (like <, >, &, ", ').
	safeKeyword := html.EscapeString(keyword)

	// 5. Write the HTML response.
	// We inject the sanitized keyword into the h2 tag as requested.
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search...</p>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on port %s", port)
	log.Printf("Try it: http://localhost%s/search?keyword=Laptop", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

