package main

import (
	"html/template"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It uses html/template to prevent Cross-Site Scripting (XSS) attacks
// by automatically escaping user input.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template.
	// The {{.}} placeholder will be replaced by the data passed to Execute.
	// html/template automatically escapes special characters (like <, >, &, ", ')
	// to prevent XSS vulnerabilities.
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("search").Parse(htmlTpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template, passing the keyword as data.
	// If the keyword contains malicious scripts (e.g., <script>...),
	// it will be rendered as harmless text (&lt;script&gt;...).
	if err := t.Execute(w, keyword); err != nil {
		// In a production environment, you would log this error.
		return
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

