import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It parses the 'keyword' query parameter, logs analytics data,
// and renders an HTML response with the search term safely escaped.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Parse input
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a real production environment, this might send data to a message queue or database.
	// Here we log the search event with timestamp, IP, and keyword.
	log.Printf("[Analytics] Search Event - Time: %s, IP: %s, Keyword: %q, User-Agent: %s",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		keyword,
		r.UserAgent(),
	)

	// 3. Prepare Response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define HTML template.
	// We use html/template to ensure the keyword is automatically escaped,
	// preventing Cross-Site Scripting (XSS) attacks.
	const pageTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the page title area -->
    <h2>Search Results: {{.}}</h2>

    <p>Showing results for your search...</p>
</body>
</html>`

	// 4. Render Template
	tmpl, err := template.New("search_page").Parse(pageTemplate)
	if err != nil {
		log.Printf("Error parsing template: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template, passing the keyword as data.
	// {{.}} in the template will be replaced by the keyword value, safely escaped.
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Error executing template: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	addr := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=golang", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

