package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes search requests, logs analytics, and renders the result page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// Log the search event. In a production environment, this might be sent 
	// to a data warehouse (e.g., BigQuery, Elasticsearch) or a message queue.
	// We use standard logging here to satisfy the requirement using only stdlib.
	log.Printf("[Analytics] Event: Search | Timestamp: %s | IP: %s | Keyword: %q",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		keyword,
	)

	// 3. Security: XSS Prevention
	// It is critical to escape user input before rendering it to HTML to prevent 
	// Cross-Site Scripting (XSS) attacks.
	safeKeyword := html.EscapeString(keyword)

	// 4. Set Response Headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Render HTML Response
	// The requirement specifies displaying the keyword in an <h2> tag.
	// We wrap it in a minimal valid HTML structure.
	responseHTML := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search...</p>
</body>
</html>`, safeKeyword)

	// Write the response
	if _, err := fmt.Fprint(w, responseHTML); err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=golang", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

