package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests.
// It captures analytics data and renders the search keyword in HTML.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the URL query parameter.
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a real-world scenario, this would send data to an analytics backend (e.g., Kafka, DB).
	// For this implementation, we log the structured event to stdout.
	log.Printf("[Analytics] Event: ProductSearch | Keyword: %q | IP: %s | Time: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Set Response Headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Render HTML Response
	// CRITICAL SECURITY STEP: We must escape the user input to prevent Cross-Site Scripting (XSS).
	// If we simply printed the keyword, a user could inject <script> tags.
	safeKeyword := html.EscapeString(keyword)

	// Write the HTML structure
	fmt.Fprintln(w, "<!DOCTYPE html>")
	fmt.Fprintln(w, "<html>")
	fmt.Fprintln(w, "<head><title>Search Page</title></head>")
	fmt.Fprintln(w, "<body>")

	// Requirement: Display the user's search keyword in the format <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)

	// Placeholder for actual product list
	if keyword != "" {
		fmt.Fprintln(w, "<p>Displaying products matching your criteria...</p>")
	} else {
		fmt.Fprintln(w, "<p>Please enter a keyword to search.</p>")
	}

	fmt.Fprintln(w, "</body>")
	fmt.Fprintln(w, "</html>")
}

func main() {
	// Register the handler function
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server starting. Try: http://localhost%s/search?keyword=Laptop", port)

	err := http.ListenAndServe(port, nil)
	if err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

