// We use html/template to automatically escape the input, preventing XSS attacks.
// This is critical when reflecting user input (the keyword) back into the HTML.
const searchTemplate = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <!-- The requirement specifies this exact format -->
    <h2>Search Results: {{.}}</h2>

    <hr>
    <p>No products found for this query (Demo).</p>
</body>
</html>`

// Pre-parse the template on startup to ensure validity and performance.
var tmpl = template.Must(template.New("searchResults").Parse(searchTemplate))

// HandleProductSearch handles the search request, logs analytics, and renders the response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Ensure we only handle GET requests for search
	if r.Method != http.MethodGet {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	// 1. Extract the keyword
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a real-world scenario, this would likely be an async call to a data warehouse
	// or an external analytics service (e.g., Kafka, Google Analytics).
	// Here, we log structured data to stdout.
	go func(query string, ip string, userAgent string) {
		log.Printf("[ANALYTICS] Event: Search | Query: %q | IP: %s | UA: %s | Time: %s",
			query,
			ip,
			userAgent,
			time.Now().Format(time.RFC3339),
		)
	}(keyword, r.RemoteAddr, r.UserAgent())

	// 3. Render the HTML response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	// Execute the template with the keyword as data.
	// template.Execute automatically escapes special characters (like <, >, &)
	// to prevent Cross-Site Scripting (XSS).
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Error rendering template: %v", err)
		// Note: We cannot write http.Error here because the status code 200 was already written.
		return
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=golang", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

