<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	t, err := template.New("search").Parse(htmlTmpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template directly to the ResponseWriter
	if err := t.Execute(w, keyword); err != nil {
		// In a real application, you would log the error here.
		return
	}
}

