package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// AnalyticsData represents the structure for capturing search metrics.
type AnalyticsData struct {
	Keyword   string
	Timestamp time.Time
	RemoteIP  string
	UserAgent string
}

// recordAnalytics simulates sending search data to an analytics backend.
// In a production environment, this might write to a database or message queue.
func recordAnalytics(r *http.Request, keyword string) {
	data := AnalyticsData{
		Keyword:   keyword,
		Timestamp: time.Now(),
		RemoteIP:  r.RemoteAddr,
		UserAgent: r.UserAgent(),
	}
	// Log to stdout to demonstrate analytics capture
	log.Printf("[Analytics] Search Event: %+v", data)
}

// HandleProductSearch handles the product search request.
// It extracts the keyword, logs analytics, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET requests for search
	if r.Method != http.MethodGet {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	// 1. Extract the search keyword
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// We run this in a goroutine to ensure analytics logging 
	// does not add latency to the user's page load.
	go recordAnalytics(r, keyword)

	// 3. HTML Response
	// We use html/template to ensure the keyword is automatically escaped.
	// This prevents Cross-Site Scripting (XSS) attacks if the keyword contains malicious scripts.
	const tplString = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the specified format -->
    <h2>Search Results: {{.}}</h2>

    <div>
        <!-- Placeholder for actual product list -->
        <p>Displaying products matching your criteria...</p>
    </div>
</body>
</html>`

	// Parse the template
	tmpl, err := template.New("search_results").Parse(tplString)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template, injecting the keyword into {{.}}
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Template execution error: %v", err)
		// Note: We cannot write http.Error here if the header has already been written
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on port 8080...")
	log.Println("Try: http://localhost:8080/search?keyword=Golang")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

