import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes the search request, records analytics, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters.
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Record the search event.
	// We log the keyword, client IP, and timestamp.
	// In a real-world scenario, this might push to a data warehouse or metrics service.
	log.Printf("[Analytics] Event: Search | Keyword: %q | Client: %s | Time: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Set the response Content-Type to HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Define the HTML structure.
	// We use the html/template package. This is critical for security.
	// It automatically escapes the input (e.g., converting <script> to &lt;script&gt;)
	// to prevent Cross-Site Scripting (XSS) attacks when reflecting user input.
	const htmlTemplate = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the h2 tag -->
    <h2>Search Results: {{.}}</h2>

    <p>Showing results for your search...</p>
</body>
</html>`

	// 5. Parse and Execute the template.
	tmpl, err := template.New("searchResults").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Error parsing template: %v", err)
		return
	}

	// Execute the template, passing the keyword as the data object ({{.}}).
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Error executing template: %v", err)
	}
}

func main() {
	// Register the handler function.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server.
	addr := ":8080"
	log.Printf("Server started. Try accessing: http://localhost%s/search?keyword=Laptop", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

