// HandleProductSearch handles the product search request.
// It parses the keyword, logs the search for analytics, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a production environment, this would likely push to a message queue or database.
	// Since we are restricted to the standard library, we log structured data to stdout.
	logAnalytics(r, keyword)

	// 3. Set Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Render the response
	// We use html/template to automatically escape the keyword, preventing XSS attacks.
	// This ensures that if a user searches for "<script>...", it is rendered as text, not executed.
	const tplString = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the page title area -->
    <h2>Search Results: {{.}}</h2>

    <!-- Placeholder for actual search results list -->
    <p><em>Displaying results for your search...</em></p>
</body>
</html>`

	tmpl, err := template.New("searchResults").Parse(tplString)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Error parsing template: %v", err)
		return
	}

	// Execute the template with the keyword as the data
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Error executing template: %v", err)
	}
}

// logAnalytics simulates an analytics tracking event using standard logging.
func logAnalytics(r *http.Request, keyword string) {
	// Log format: [Timestamp] [IP] [UserAgent] [Action] [Keyword]
	log.Printf(
		"ANALYTICS | IP: %s | UA: %s | Action: Search | Keyword: %q",
		r.RemoteAddr,
		r.UserAgent(),
		keyword,
	)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Configure the server
	server := &http.Server{
		Addr:         ":8080",
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 10 * time.Second,
		Handler:      nil, // Use DefaultServeMux
	}

	log.Println("Server starting on http://localhost:8080")
	log.Println("Try visiting: http://localhost:8080/search?keyword=Golang")

	// Start the server
	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

