package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It extracts the keyword, logs analytics data, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// Log the search event with timestamp, keyword, and client IP.
	// In a real-world scenario, this might push to a message queue or database.
	log.Printf("[Analytics] Event: Search | Keyword: %q | IP: %s | Time: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Set Response Headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Security: Input Sanitization
	// Crucial: Escape the user input to prevent Cross-Site Scripting (XSS) attacks.
	// Since we are reflecting user input directly into the HTML, we must use html.EscapeString.
	safeKeyword := html.EscapeString(keyword)

	// 5. Construct HTML Response
	// Using fmt.Sprintf for simplicity while adhering to standard library constraints.
	// The requirement is to display: <h2>Search Results: [keyword]</h2>
	responseHTML := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 2rem; }
        .product-list { margin-top: 1rem; border-top: 1px solid #ccc; }
        .item { padding: 0.5rem 0; border-bottom: 1px solid #eee; }
    </style>
</head>
<body>
    <!-- Required Output Format -->
    <h2>Search Results: %s</h2>

    <div class="product-list">
        <p><em>Analytics logged. Displaying mock results for "%s"...</em></p>
        <div class="item">Product A</div>
        <div class="item">Product B</div>
        <div class="item">Product C</div>
    </div>
</body>
</html>`, safeKeyword, safeKeyword)

	// 6. Write Response
	w.WriteHeader(http.StatusOK)
	if _, err := w.Write([]byte(responseHTML)); err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define port
	port := ":8080"
	fmt.Printf("Server is running. Access http://localhost%s/search?keyword=laptop\n", port)

	// Start server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal("Server failed to start: ", err)
	}
}

