import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It extracts the keyword, logs analytics data, and renders the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// We log the search event with relevant metadata (Timestamp, IP, User Agent, Keyword).
	// In a production environment, this might be sent to a Kafka topic or an analytics service.
	log.Printf(
		"ANALYTICS_EVENT: type=search timestamp=%s ip=%s user_agent=%q keyword=%q",
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
		keyword,
	)

	// 3. Define the HTML Template
	// We use html/template to ensure the keyword is properly escaped, preventing XSS attacks.
	const htmlTpl = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <!-- Requirement: Display the user's search keyword in the page title area -->
    <h2>Search Results: {{.}}</h2>

    <hr>
    <div>
        <p><em>Displaying products matching your query...</em></p>
    </div>
</body>
</html>`

	// 4. Parse the template
	tmpl, err := template.New("search_page").Parse(htmlTpl)
	if err != nil {
		log.Printf("Error parsing template: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// 5. Write the response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the keyword as the data object.
	// {{.}} in the template will be replaced by the keyword value, HTML-escaped.
	if err := tmpl.Execute(w, keyword); err != nil {
		log.Printf("Error rendering template: %v", err)
		// Note: We cannot send http.Error here if the header has already been written
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on port 8080...")
	log.Println("Try: http://localhost:8080/search?keyword=Golang")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

